'use client';

import { useState } from 'react';
import Link from 'next/link';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Logo } from '@/components/logo';
import { AlertCircle, Loader2, MailCheck, ArrowLeft } from 'lucide-react';
import { Alert, AlertDescription } from '@/components/ui/alert';

import { TechAuthBackground } from '@/components/ui-patterns/tech-auth-bg';
import { motion, AnimatePresence } from 'framer-motion';

export default function ForgotPasswordPage() {
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const res = await fetch('/api/auth/forgot-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || 'Something went wrong');
      }

      setSuccess(true);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="relative min-h-screen flex items-center justify-center px-4 py-12 overflow-hidden">
      <TechAuthBackground />

      <AnimatePresence mode="wait">
        {success ? (
          <motion.div
            key="success"
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="w-full max-w-sm z-10"
          >
            <Card className="backdrop-blur-xl bg-white/90 dark:bg-slate-900/90 border-brand/20 shadow-2xl text-center p-8">
              <CardHeader>
                <motion.div
                  initial={{ rotate: -20, opacity: 0 }}
                  animate={{ rotate: 0, opacity: 1 }}
                >
                  <MailCheck className="h-16 w-16 text-brand mx-auto mb-4" />
                </motion.div>
                <CardTitle className="text-2xl font-black uppercase tracking-tight">Reset Link Sent</CardTitle>
                <CardDescription className="font-medium">
                  Check your corporate inbox for recovery instructions.
                </CardDescription>
              </CardHeader>
              <CardContent>
                <Button asChild className="w-full h-12 bg-brand hover:bg-brand/90 font-bold uppercase tracking-widest">
                  <Link href="/login">Return to Login</Link>
                </Button>
              </CardContent>
            </Card>
          </motion.div>
        ) : (
          <motion.div
            key="form"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="w-full max-w-sm z-10"
          >
            <Card className="backdrop-blur-xl bg-white/90 dark:bg-slate-900/90 border-white/10 shadow-2xl">
              <CardHeader className="text-center">
                <Logo className="justify-center mb-6" />
                <CardTitle className="text-2xl font-black uppercase tracking-tight">Forgot Password?</CardTitle>
                <CardDescription className="font-medium">
                  Enter your email to receive a secure recovery link.
                </CardDescription>
              </CardHeader>
              <CardContent className="pt-4">
                {error && (
                  <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
                    <Alert variant="destructive" className="mb-6 border-destructive/20 bg-destructive/5">
                      <AlertCircle className="h-4 w-4" />
                      <AlertDescription>{error}</AlertDescription>
                    </Alert>
                  </motion.div>
                )}

                <form onSubmit={handleSubmit} className="space-y-5">
                  <div className="space-y-2">
                    <Label className="text-xs font-bold uppercase tracking-wider text-slate-500">Corporate Email</Label>
                    <Input
                      id="email"
                      type="email"
                      placeholder="john@example.com"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      required
                      disabled={isLoading}
                      className="h-12 bg-slate-50/50 dark:bg-slate-800/50"
                    />
                  </div>
                  <Button type="submit" className="w-full h-12 bg-brand hover:bg-brand/90 text-white font-bold uppercase tracking-widest transition-all" disabled={isLoading}>
                    {isLoading ? (
                      <>
                        <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                        Sending...
                      </>
                    ) : (
                      'Request Reset Link'
                    )}
                  </Button>
                </form>
                <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 text-center text-sm">
                  <Link
                    href="/login"
                    className="flex items-center justify-center gap-2 text-muted-foreground hover:text-brand font-bold transition-colors uppercase tracking-tighter"
                  >
                    <ArrowLeft className="h-4 w-4" />
                    Back to Sign In
                  </Link>
                </div>
              </CardContent>
            </Card>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

